const d = $input.first().json;
const pr = d.provisioning_results || {};
const notif = d.notification_results || {};

// Build 22-column audit row in sheet column order.
// Sheet column headers (row 1) must match this order exactly — see SETUP.md §5.
// valueInputOption RAW (configured on the Sheets node) prevents formula injection.
const row = {
  hire_id:                     d.hire_id                    || '',
  full_name:                   d.full_name                  || '',
  personal_email:              d.personal_email             || '',
  job_title:                   d.job_title                  || '',
  department:                  d.department                 || '',
  role_group:                  d.role_group                 || '',
  employment_type:             d.employment_type            || '',
  start_date:                  d.start_date                 || '',
  manager_email:               d.manager_email              || '',
  source_system:               d.source_system              || '',
  it_approved_by:              d.it_approved_by             || '',
  it_approved_at:              d.it_approved_at             || '',
  gsuite_status:               pr.gsuite                    || 'NOT_RUN',
  slack_status:                pr.slack                     || 'NOT_RUN',
  notion_status:               pr.notion                    || 'NOT_RUN',
  additional_tools_status:     JSON.stringify(pr.additional || {}),
  welcome_email_sent:          notif.welcome_email_sent     ? 'TRUE' : 'FALSE',
  manager_notified:            notif.manager_notified       ? 'TRUE' : 'FALSE',
  clickup_checklist_created:   d.clickup_checklist_created  ? 'TRUE' : 'FALSE',
  check_ins_scheduled:         String(d.check_ins_scheduled || 0),
  pipeline_started_at:         d.pipeline_started_at        || '',
  pipeline_completed_at:       new Date().toISOString()
};

return [{ json: row }];
